func TestEnumDatasetStatus(t *testing.T) {
	t.Run("NewFromString_ACTIVE", func(t *testing.T) {
		t.Parallel()
		val, err := NewDatasetStatusFromString("ACTIVE")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, DatasetStatus("ACTIVE"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_ARCHIVED", func(t *testing.T) {
		t.Parallel()
		val, err := NewDatasetStatusFromString("ARCHIVED")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, DatasetStatus("ARCHIVED"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewDatasetStatusFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewDatasetStatusFromString("ACTIVE")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

